                'PMA_MYSQL_INT_VERSION',
                PMA_MYSQL_INT_VERSION
            );
            PMA_Util::cacheSet(
                'PMA_MYSQL_MAJOR_VERSION',
                PMA_MYSQL_MAJOR_VERSION
            );
            PMA_Util::cacheSet(
